(189, 'Bugis Seafood Bee Hoon', 'Seafood', '$', 'Bugis', '4.2', 'https://images.unsplash.com/photo-1519984388953-d2406bc725e1?w=600&q=80', 'White bee hoon with clams and prawns in a collagen-rich seafood broth.'),
(190, 'Bugis Western Casual', 'Western', '$$', 'Bugis', '4.0', 'https://images.unsplash.com/photo-1432139509613-5c4255815697?w=600&q=80', 'Casual western food near the arts district. Good pasta and reliable chicken chop.'),
(191, 'Tanjong Pagar Japanese Soba', 'Japanese', '$$', 'Tanjong Pagar', '4.4', 'https://images.unsplash.com/photo-1504544750208-dc0358e63f7f?w=600&q=80', 'Artisanal buckwheat soba served chilled with wasabi and dipping tsuyu.'),
(192, 'Tanjong Pagar Vegan Garden', 'Vegan', '$$', 'Tanjong Pagar', '4.2', 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=600&q=80', 'Bright garden-themed vegan cafe with tempeh bowls and house-fermented kombucha.'),
(193, 'Tanjong Pagar Seafood Grill', 'Seafood', '$$$', 'Tanjong Pagar', '4.5', 'https://images.unsplash.com/photo-1606728035253-49e8a23146de?w=600&q=80', 'Whole fish grilled over wood fire with fresh herbs and charred lemon. Simple perfection.'),
(194, 'Tanjong Pagar Italian Wine', 'Italian', '$$$', 'Tanjong Pagar', '4.3', 'https://images.unsplash.com/photo-1516100882582-96c3a05fe590?w=600&q=80', 'Wine-forward Italian with a cellar of 400 labels and exceptional handmade pasta.'),
(195, 'Tanjong Pagar Indian Spice', 'Indian', '$', 'Tanjong Pagar', '4.1', 'https://images.unsplash.com/photo-1588166524941-3bf61a9c41db?w=600&q=80', 'Spice-laden South Indian cooking near the CBD. Busy lunch spot for office workers.'),
(196, 'Novena Seafood Grill', 'Seafood', '$$$', 'Novena', '4.4', 'https://images.unsplash.com/photo-1576867757603-05b134ebc379?w=600&q=80', 'Upscale seafood grill with market-price live lobster and seasonal oysters.'),
(197, 'Novena Vegan Diner', 'Vegan', '$', 'Novena', '4.0', 'https://images.unsplash.com/photo-1543352634-a1c51d9f1fa7?w=600&q=80', 'Unpretentious vegan diner with hearty all-day breakfast and plant-based burgers.'),
(198, 'Novena Korean Galbi', 'Korean', '$$$', 'Novena', '4.5', 'https://images.unsplash.com/photo-1527477396000-e27163b481c2?w=600&q=80', 'Slow-marinated short ribs grilled to perfection. The bone-in galbi is a must-order.'),
(199, 'Novena Italian Trattoria', 'Italian', '$$$', 'Novena', '4.3', 'https://images.unsplash.com/photo-1473093226795-af9932fe5856?w=600&q=80', 'Neighbourhood trattoria with housemade pasta, fresh burrata, and good house wine.'),
(200, 'Novena Chinese Hotpot', 'Chinese', '$$', 'Novena', '4.2', 'https://images.unsplash.com/photo-1525755662778-989d0524087e?w=600&q=80', 'Sichuan and herbal soup bases for a fiery or soothing hotpot experience.'),
(201, 'Holland Village Seafood Grill', 'Seafood', '$$$', 'Holland Village', '4.5', 'https://images.unsplash.com/photo-1551504734-5ee1c4a1479b?w=600&q=80', 'Fresh seafood and cold-water oysters in Holland V most upscale dining room.'),
(202, 'Holland Village Ramen House', 'Japanese', '$$', 'Holland Village', '4.3', 'https://images.unsplash.com/photo-1617196034302-fc5a87a66e84?w=600&q=80', 'Cosy ramen house with a rotating seasonal menu. Try the truffle mazemen.'),
(203, 'Holland Village Italian Wine Bar', 'Italian', '$$$', 'Holland Village', '4.4', 'https://images.unsplash.com/photo-1574071318508-1cdbab80d002?w=600&q=80', 'Natural wine bar with charcuterie and pasta. The perfect pre-dinner spot.'),
(204, 'Holland Village Local Kopitiam', 'Local', '$', 'Holland Village', '4.2', 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=600&q=80', 'Old-school kopitiam with kaya toast, soft boiled eggs, and strong local coffee.'),
(205, 'Holland Village Chinese Roast', 'Chinese', '$$', 'Holland Village', '4.4', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?w=600&q=80', 'Cantonese roasted meats sliced to order. Char siu with honeyed glaze is exceptional.'),
