(210, 'Dempsey Vegan Forest', 'Vegan', '$$', 'Dempsey', '4.1', 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=600&q=80', 'Forested vegan garden restaurant. Mushroom-based dishes that taste like pure earth.'),
(211, 'East Coast Peranakan House', 'Local', '$$', 'East Coast', '4.5', 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=600&q=80', 'Authentic babi ponteh and itek tim in a heritage house with open-air courtyard.'),
(212, 'East Coast Seafood Village', 'Seafood', '$$$', 'East Coast', '4.6', 'https://images.unsplash.com/photo-1498654896293-37aacf113fd9?w=600&q=80', 'The original East Coast Park seafood — chilli crab, butter crab, and pepper crab.'),
(213, 'East Coast Japanese Garden', 'Japanese', '$$$', 'East Coast', '4.4', 'https://images.unsplash.com/photo-1547592166-23ac45744acd?w=600&q=80', 'Garden omakase experience with seasonal kaiseki courses. Serene and refined.'),
