(215, 'East Coast Vegan Hut', 'Vegan', '$', 'East Coast', '4.0', 'https://images.unsplash.com/photo-1505576399279-565b52d4ac71?w=600&q=80', 'Beachside vegan snack hut with smoothies, wraps, and coconut bowls.'),
(216, 'Harbourfront Italian Quay', 'Italian', '$$$', 'Harbourfront', '4.4', 'https://images.unsplash.com/photo-1555949258-eb67b1ef0ceb?w=600&q=80', 'Quayside Italian with ferry views and handmade pasta. The seafood linguine excels.'),
(217, 'Harbourfront Korean Spot', 'Korean', '$$', 'Harbourfront', '4.2', 'https://images.unsplash.com/photo-1535399831218-d5bd36d1a6b3?w=600&q=80', 'Casual Korean near VivoCity with affordable tofu stews and bibimbap.'),
(218, 'Harbourfront Indian Garden', 'Indian', '$$', 'Harbourfront', '4.1', 'https://images.unsplash.com/photo-1596797038530-2c107229654b?w=600&q=80', 'Southern Indian curry house with a stunning harbour view from the upper deck.'),
(219, 'Harbourfront Local Hawker', 'Local', '$', 'Harbourfront', '4.3', 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=600&q=80', 'Hawker centre with a stunning view of Sentosa. The char kway teow is stellar.'),
(220, 'Harbourfront Thai Breeze', 'Thai', '$$', 'Harbourfront', '4.2', 'https://images.unsplash.com/photo-1559314809-0d155014e29e?w=600&q=80', 'Breezy Thai dining near the ferry terminal. Great for a meal before Batam.'),
(221, 'Orchard Road Rooftop Brunch', 'Western', '$$$', 'Orchard', '4.5', 'https://images.unsplash.com/photo-1509440159596-0249088772ff?w=600&q=80', 'Rooftop brunch with infinity-edge pool views and a spectacular eggs royale.'),
(222, 'Orchard Local Hawker Fine', 'Local', '$$', 'Orchard', '4.3', 'https://images.unsplash.com/photo-1567620905732-2d1ec7ab7445?w=600&q=80', 'Hawker dishes elevated with premium ingredients. Chilli crab pasta is a revelation.'),
(223, 'Orchard Seafood Terrace', 'Seafood', '$$$', 'Orchard', '4.6', 'https://images.unsplash.com/photo-1519984388953-d2406bc725e1?w=600&q=80', 'Penthouse seafood restaurant overlooking the shopping belt. Live lobster daily.'),
(224, 'Orchard Indian Fine Dining', 'Indian', '$$$', 'Orchard', '4.5', 'https://images.unsplash.com/photo-1488900128323-21503983a07e?w=600&q=80', 'Progressive Indian cuisine with molecular techniques and heritage spice blends.'),
(225, 'Orchard Vegan Concept Store', 'Vegan', '$$', 'Orchard', '4.2', 'https://images.unsplash.com/photo-1540914124281-342587941389?w=600&q=80', 'Stylish vegan concept combining plant-based food with lifestyle retail.');
