(231, 'Toa Payoh Vegan Lunch Box', 'Vegan', '$', 'Toa Payoh', '3.8', 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=600&q=80', 'Budget vegan lunch boxes for office workers. Healthy and surprisingly filling.'),
(232, 'Toa Payoh Chinese Roast', 'Chinese', '$', 'Toa Payoh', '4.3', 'https://images.unsplash.com/photo-1525755662778-989d0524087e?w=600&q=80', 'Roasted pork belly with crackling so crispy it shatters on first bite.'),
(233, 'Toa Payoh Western Cafe', 'Western', '$$', 'Toa Payoh', '4.0', 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=600&q=80', 'Cosy neighbourhood cafe with good coffee, hearty sandwiches, and weekend specials.'),
